#include<stdio.h>
int main(){
int n,m,a,b,i,count,count1=0,count2,count3;
scanf("%d %d %d %d",&n,&m,&a,&b);
count=n*a;
if(n%m==0){count3=(n/m)*b;}
else{count3=((n/m)+1)*b;}
while(n>=0){
    if(n>m){
        n=n-m;
        count1=count1+b;
    }
    else{
        count2=count1+n*a;
        count1=count1+b;
        n=n-n;
    }
    if(n==0){break;}
}

if(count<=count1&&count<=count2&&count<=count3){
    printf("%d",count);
}
else if(count1<count&&count1<=count2&&count1<=count3){
    printf("%d",count1);
}
else if(count2<count&&count2<count1&&count2<=count3){
    printf("%d",count2);
}
else if(count3<count&&count3<count1&&count3<count2){
    printf("%d",count3);
}
}

